import { config } from "./config.js";
import { migrateCurve } from "./migrate.js";
import { fetchActionableCurves, validateGlobalConfig } from "./program.js";
import { StateStore } from "./state.js";

const store = new StateStore(config.stateFile);
await store.load();
await validateGlobalConfig();
console.log(`Migrator ${config.authority.publicKey.toBase58()} watching program ${config.programId.toBase58()}`);
console.log(`CORE mint: ${config.coreMint.toBase58()}`);

let running = false;
async function tick() {
  if (running) return;
  running = true;
  try {
    const curves = await fetchActionableCurves();
    for (const row of curves) {
      try {
        console.log(`Processing ${row.publicKey.toBase58()} status=${row.account.status}`);
        await migrateCurve(row.publicKey, row.account, store);
      } catch (error) {
        console.error(`Migration failed for ${row.publicKey.toBase58()}`, error);
      }
    }
  } catch (error) {
    console.error("Migration scan failed", error);
  } finally { running = false; }
}

await tick();
setInterval(tick, config.pollIntervalMs);

import { VersionedTransaction } from "@solana/web3.js";
import bs58 from "bs58";
import { config } from "./config.js";

type OrderResponse = {
  transaction?: string;
  requestId?: string;
  outAmount?: string;
  lastValidBlockHeight?: string;
  error?: string;
  errorMessage?: string;
};

type ExecuteResponse = {
  status: "Success" | "Failed";
  signature?: string;
  outputAmountResult?: string;
  error?: string;
  code?: number;
};

export type PreparedSwap = {
  signedTransaction: string;
  requestId: string;
  lastValidBlockHeight?: string;
  signature: string;
  quotedCoreAmount: bigint;
};

export async function prepareSolToCoreSwap(amountLamports: bigint): Promise<PreparedSwap> {
  const query = new URLSearchParams({
    inputMint: "So11111111111111111111111111111111111111112",
    outputMint: config.coreMint.toBase58(),
    amount: amountLamports.toString(),
    taker: config.authority.publicKey.toBase58(),
    slippageBps: String(config.slippageBps),
  });
  const response = await fetch(`https://api.jup.ag/swap/v2/order?${query}`, {
    headers: { "x-api-key": config.jupiterApiKey },
  });
  if (!response.ok) throw new Error(`Jupiter order failed: ${response.status} ${await response.text()}`);
  const order = await response.json() as OrderResponse;
  if (!order.transaction || !order.requestId) {
    throw new Error(order.errorMessage ?? order.error ?? "Jupiter returned no transaction");
  }

  const tx = VersionedTransaction.deserialize(Buffer.from(order.transaction, "base64"));
  tx.sign([config.authority]);
  const quotedCoreAmount = BigInt(order.outAmount ?? "0");
  if (quotedCoreAmount <= 0n) throw new Error("Jupiter quoted zero CORE output");

  return {
    signedTransaction: Buffer.from(tx.serialize()).toString("base64"),
    requestId: order.requestId,
    lastValidBlockHeight: order.lastValidBlockHeight,
    signature: bs58.encode(tx.signatures[0]),
    quotedCoreAmount,
  };
}

export async function executePreparedSwap(prepared: PreparedSwap): Promise<{ signature: string; reportedCoreAmount: bigint }> {
  const response = await fetch("https://api.jup.ag/swap/v2/execute", {
    method: "POST",
    headers: { "Content-Type": "application/json", "x-api-key": config.jupiterApiKey },
    body: JSON.stringify({
      signedTransaction: prepared.signedTransaction,
      requestId: prepared.requestId,
      lastValidBlockHeight: prepared.lastValidBlockHeight,
    }),
  });
  if (!response.ok) throw new Error(`Jupiter execute failed: ${response.status} ${await response.text()}`);
  const result = await response.json() as ExecuteResponse;
  if (result.status !== "Success") {
    throw new Error(`Jupiter swap failed: ${result.code ?? ""} ${result.error ?? "unknown error"}`);
  }
  return {
    signature: result.signature ?? prepared.signature,
    reportedCoreAmount: BigInt(result.outputAmountResult ?? prepared.quotedCoreAmount.toString()),
  };
}
